package handlers

import (
	"encoding/json"
	"net/http"
	"strings"
)

type FailureReason string

const (
	ReasonMethodNotAllowed       FailureReason = "METHOD_NOT_ALLOWED"
	ReasonInvalidRequest         FailureReason = "INVALID_REQUEST"
	ReasonInvalidToken           FailureReason = "INVALID_TOKEN"
	ReasonAuthorizationDenied    FailureReason = "AUTHORIZATION_DENIED"
	ReasonPasswordChangeRequired FailureReason = "PASSWORD_CHANGE_REQUIRED"
	ReasonNotFound               FailureReason = "NOT_FOUND"
	ReasonRateLimited            FailureReason = "RATE_LIMITED"
	ReasonLoginRateLimited       FailureReason = "LOGIN_RATE_LIMITED"
	ReasonUserNotFound           FailureReason = "USER_NOT_FOUND"
	ReasonMarketNotFound         FailureReason = "MARKET_NOT_FOUND"

	ReasonValidationFailed    FailureReason = "VALIDATION_FAILED"
	ReasonMarketClosed        FailureReason = "MARKET_CLOSED"
	ReasonInsufficientBalance FailureReason = "INSUFFICIENT_BALANCE"
	ReasonNoPosition          FailureReason = "NO_POSITION"
	ReasonInsufficientShares  FailureReason = "INSUFFICIENT_SHARES"
	ReasonDustCapExceeded     FailureReason = "DUST_CAP_EXCEEDED"
	ReasonInternalError       FailureReason = "INTERNAL_ERROR"
)

var publicFailureReasons = []FailureReason{
	ReasonMethodNotAllowed,
	ReasonInvalidRequest,
	ReasonInvalidToken,
	ReasonAuthorizationDenied,
	ReasonPasswordChangeRequired,
	ReasonNotFound,
	ReasonRateLimited,
	ReasonLoginRateLimited,
	ReasonUserNotFound,
	ReasonMarketNotFound,
	ReasonValidationFailed,
	ReasonMarketClosed,
	ReasonInsufficientBalance,
	ReasonNoPosition,
	ReasonInsufficientShares,
	ReasonDustCapExceeded,
	ReasonInternalError,
}

// PublicFailureReasons returns the shared public reason vocabulary for the
// touched API envelope routes.
func PublicFailureReasons() []FailureReason {
	return append([]FailureReason(nil), publicFailureReasons...)
}

type SuccessEnvelope[T any] struct {
	OK     bool `json:"ok"`
	Result T    `json:"result"`
}

type FailureEnvelope struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

func WriteResult[T any](w http.ResponseWriter, statusCode int, result T) error {
	return writeJSON(w, statusCode, SuccessEnvelope[T]{
		OK:     true,
		Result: result,
	})
}

func WriteFailure(w http.ResponseWriter, statusCode int, reason FailureReason) error {
	return writeJSON(w, statusCode, FailureEnvelope{
		OK:     false,
		Reason: string(reason),
	})
}

func WriteBusinessFailure(w http.ResponseWriter, reason FailureReason) error {
	return WriteFailure(w, http.StatusOK, reason)
}

func IsValidationMessage(message string) bool {
	lower := strings.ToLower(message)
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required")
}

func writeJSON(w http.ResponseWriter, statusCode int, payload any) error {
	body, err := json.Marshal(payload)
	if err != nil {
		return err
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_, err = w.Write(append(body, '\n'))
	return err
}
package authhttp

import (
	"net/http"

	"socialpredict/handlers"
	authsvc "socialpredict/internal/service/auth"
)

func StatusCode(err *authsvc.AuthError) int {
	if err == nil {
		return http.StatusInternalServerError
	}

	switch err.Kind {
	case authsvc.ErrorKindMissingToken, authsvc.ErrorKindInvalidToken:
		return http.StatusUnauthorized
	case authsvc.ErrorKindUserNotFound:
		return http.StatusNotFound
	case authsvc.ErrorKindPasswordChangeRequired, authsvc.ErrorKindAdminRequired:
		return http.StatusForbidden
	case authsvc.ErrorKindUserLoadFailed, authsvc.ErrorKindServiceUnavailable:
		return http.StatusInternalServerError
	default:
		return http.StatusInternalServerError
	}
}

func FailureReason(err *authsvc.AuthError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Kind {
	case authsvc.ErrorKindMissingToken, authsvc.ErrorKindInvalidToken:
		return handlers.ReasonInvalidToken
	case authsvc.ErrorKindUserNotFound:
		return handlers.ReasonUserNotFound
	case authsvc.ErrorKindPasswordChangeRequired:
		return handlers.ReasonPasswordChangeRequired
	case authsvc.ErrorKindAdminRequired:
		return handlers.ReasonAuthorizationDenied
	case authsvc.ErrorKindUserLoadFailed, authsvc.ErrorKindServiceUnavailable:
		return handlers.ReasonInternalError
	default:
		return handlers.ReasonInternalError
	}
}

func WriteFailure(w http.ResponseWriter, err *authsvc.AuthError) error {
	return handlers.WriteFailure(w, StatusCode(err), FailureReason(err))
}
package security

import (
	"net/http"
	"sync"
	"time"

	"golang.org/x/time/rate"

	boundaryerrors "socialpredict/errors"
)

// RateLimiter manages rate limiting for different clients/IPs
type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
	cleanup  time.Duration
}

// NewRateLimiter creates a new rate limiter
func NewRateLimiter(r rate.Limit, b int, cleanup time.Duration) *RateLimiter {
	rl := &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
		cleanup:  cleanup,
	}

	// Start cleanup goroutine
	go rl.cleanupRoutine()

	return rl
}

// GetLimiter returns the rate limiter for a given key (IP address)
func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}

	return limiter
}

// cleanupRoutine periodically removes unused limiters
func (rl *RateLimiter) cleanupRoutine() {
	ticker := time.NewTicker(rl.cleanup)
	defer ticker.Stop()

	for range ticker.C {
		rl.mu.Lock()
		for key, limiter := range rl.limiters {
			// Remove limiters that haven't been used recently
			if limiter.TokensAt(time.Now()) == float64(rl.burst) {
				delete(rl.limiters, key)
			}
		}
		rl.mu.Unlock()
	}
}

// RateLimitConfig holds configuration for different rate limits
type RateLimitConfig struct {
	LoginRate       rate.Limit // requests per second for login attempts
	LoginBurst      int        // max burst for login attempts
	GeneralRate     rate.Limit // requests per second for general API
	GeneralBurst    int        // max burst for general API
	CleanupInterval time.Duration
}

// DefaultRateLimitConfig returns sensible default rate limits
func DefaultRateLimitConfig() RateLimitConfig {
	return RateLimitConfig{
		LoginRate:       rate.Every(10 * time.Second), // 1 login attempt per 10 seconds
		LoginBurst:      3,                            // Allow burst of 3 attempts
		GeneralRate:     rate.Every(time.Second),      // 1 request per second
		GeneralBurst:    10,                           // Allow burst of 10 requests
		CleanupInterval: 5 * time.Minute,              // Cleanup every 5 minutes
	}
}

// RateLimitMiddleware creates a rate limiting middleware
func RateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				boundaryerrors.WriteRateLimited(w, boundaryerrors.RuntimeReasonRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// LoginRateLimitMiddleware creates a stricter rate limit for login endpoints
func LoginRateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				boundaryerrors.WriteRateLimited(w, boundaryerrors.RuntimeReasonLoginRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// getClientIP extracts the client IP address from the request
func getClientIP(r *http.Request) string {
	// Check for forwarded IP first (if behind proxy)
	forwarded := r.Header.Get("X-Forwarded-For")
	if forwarded != "" {
		// X-Forwarded-For can contain multiple IPs, get the first one
		if idx := len(forwarded); idx > 0 {
			if commaIdx := 0; commaIdx < idx {
				for i, c := range forwarded {
					if c == ',' {
						commaIdx = i
						break
					}
				}
				if commaIdx > 0 {
					return forwarded[:commaIdx]
				}
			}
			return forwarded
		}
	}

	// Check for real IP header
	if realIP := r.Header.Get("X-Real-IP"); realIP != "" {
		return realIP
	}

	// Fall back to remote address
	return r.RemoteAddr
}

// RateLimitManager manages multiple rate limiters for different endpoints
type RateLimitManager struct {
	loginLimiter   *RateLimiter
	generalLimiter *RateLimiter
}

// NewRateLimitManager creates a new rate limit manager with default configuration
func NewRateLimitManager() *RateLimitManager {
	config := DefaultRateLimitConfig()

	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// NewCustomRateLimitManager creates a rate limit manager with custom configuration
func NewCustomRateLimitManager(config RateLimitConfig) *RateLimitManager {
	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// GetLoginMiddleware returns the login rate limiting middleware
func (rlm *RateLimitManager) GetLoginMiddleware() func(http.Handler) http.Handler {
	return LoginRateLimitMiddleware(rlm.loginLimiter)
}

// GetGeneralMiddleware returns the general rate limiting middleware
func (rlm *RateLimitManager) GetGeneralMiddleware() func(http.Handler) http.Handler {
	return RateLimitMiddleware(rlm.generalLimiter)
}
