// CORS helpers configured via environment variables

func getListEnv(key, def string) []string { // default empty - allows any string, splits on comma
	val := strings.TrimSpace(os.Getenv(key))
	if val == "" {
		val = def
	}
	if val == "" {
		return nil
	}
	parts := strings.Split(val, ",")
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

func getBoolEnv(key string, def bool) bool { // default false - allows any string to be false except specific true values
	v := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
	if v == "" {
		return def
	}
	return v == "1" || v == "true" || v == "yes" || v == "on"
}

func getIntEnv(key string, def int) int { // default 0 - allows any string to be int, otherwise default
	v := strings.TrimSpace(os.Getenv(key))
	if v == "" {
		return def
	}
	if n, err := strconv.Atoi(v); err == nil {
		return n
	}
	return def
}

func buildCORSFromEnv() *cors.Cors {
	if !getBoolEnv("CORS_ENABLED", true) {
		return nil
	}
	origins := getListEnv("CORS_ALLOW_ORIGINS", "*")
	methods := getListEnv("CORS_ALLOW_METHODS", "GET,POST,PUT,PATCH,DELETE,OPTIONS")
	headers := getListEnv("CORS_ALLOW_HEADERS", "Content-Type,Authorization")
	expose := getListEnv("CORS_EXPOSE_HEADERS", "")
	allowCreds := getBoolEnv("CORS_ALLOW_CREDENTIALS", false)
	maxAge := getIntEnv("CORS_MAX_AGE", 600)

	return cors.New(cors.Options{
		AllowedOrigins:   origins,
		AllowedMethods:   methods,
		AllowedHeaders:   headers,
		ExposedHeaders:   expose,
		AllowCredentials: allowCreds,
		MaxAge:           maxAge,
	})
}

func buildHandler(openAPISpec []byte, swaggerUIFS fs.FS, db *gorm.DB, configService configsvc.Service, readiness *appruntime.Readiness) (http.Handler, error) {
	router, err := buildRouter(openAPISpec, swaggerUIFS, db, configService, readiness)
	if err != nil {
		return nil, err
	}

	handler := http.Handler(router)
	if c := buildCORSFromEnv(); c != nil {
		handler = c.Handler(handler)
	}
	handler = security.RequestBoundaryMiddleware()(handler)

	return handler, nil
}

func buildRouter(openAPISpec []byte, swaggerUIFS fs.FS, db *gorm.DB, configService configsvc.Service, readiness *appruntime.Readiness) (*mux.Router, error) {
	if configService == nil {
		return nil, fmt.Errorf("config init: configuration service unavailable")
	}

	router := mux.NewRouter()
	router.MethodNotAllowedHandler = methodNotAllowedHandler(router)
	if err := registerInfraRoutes(router, openAPISpec, swaggerUIFS, db, readiness); err != nil {
		return nil, err
	}

	registerApplicationRoutes(router, db, configService, security.NewSecurityService())
	return router, nil
}

func methodNotAllowedHandler(router *mux.Router) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if allow := strings.Join(allowedMethodsForRequest(router, r), ", "); allow != "" {
			w.Header().Set("Allow", allow)
		}
		boundaryerrors.WriteMethodNotAllowed(w)
	})
}

func allowedMethodsForRequest(router *mux.Router, r *http.Request) []string {
	if router == nil || r == nil {
		return nil
	}

	methodSet := make(map[string]struct{})

	_ = router.Walk(func(route *mux.Route, _ *mux.Router, _ []*mux.Route) error {
		methods, err := route.GetMethods()
		if err != nil || len(methods) == 0 {
			return nil
		}

		for _, method := range methods {
			candidate := r.Clone(r.Context())
			candidate.Method = method

			var match mux.RouteMatch
			if route.Match(candidate, &match) {
				for _, matchedMethod := range methods {
					methodSet[matchedMethod] = struct{}{}
				}
				break
			}
		}

		return nil
	})

	if len(methodSet) == 0 {
		return nil
	}

	allowed := make([]string, 0, len(methodSet))
	for method := range methodSet {
		allowed = append(allowed, method)
	}
	sort.Strings(allowed)
	return allowed
}

const readinessProbeTimeout = 2 * time.Second

type applicationReportingService interface {
	metricshandlers.SystemMetricsService
	metricshandlers.GlobalLeaderboardService
}

func registerInfraRoutes(router *mux.Router, openAPISpec []byte, swaggerUIFS fs.FS, db *gorm.DB, readiness *appruntime.Readiness) error {
	router.HandleFunc("/health", healthHandler).Methods("GET")
	router.Handle("/readyz", readinessHandler(db, readiness)).Methods("GET")

	// OpenAPI spec endpoint
	router.HandleFunc("/openapi.yaml", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/yaml; charset=utf-8")
		_, _ = w.Write(openAPISpec)
	}).Methods("GET")

	// Swagger UI endpoints
	// Redirect /swagger -> /swagger/
	router.HandleFunc("/swagger", func(w http.ResponseWriter, r *http.Request) {
		http.Redirect(w, r, "/swagger/", http.StatusMovedPermanently)
	})
	// File server rooted at swagger-ui/
	uiFS, err := fs.Sub(swaggerUIFS, "swagger-ui")
	if err != nil {
		return fmt.Errorf("failed to set up swagger-ui FS: %w", err)
	}
	swaggerHandler := http.FileServer(http.FS(uiFS))
	router.PathPrefix("/swagger/").Handler(http.StripPrefix("/swagger/", swaggerHandler))

	return nil
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	writeProbeResponse(w, http.StatusOK, "ok")
}

func readinessHandler(db *gorm.DB, readiness *appruntime.Readiness) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if readiness == nil || !readiness.Ready() {
			writeProbeResponse(w, http.StatusServiceUnavailable, "not ready")
			return
		}
		ctx, cancel := context.WithTimeout(r.Context(), readinessProbeTimeout)
		defer cancel()
		if err := appruntime.CheckDBReadiness(ctx, db); err != nil {
			writeProbeResponse(w, http.StatusServiceUnavailable, "not ready")
			return
		}

		writeProbeResponse(w, http.StatusOK, "ready")
	})
}

package security

import (
	"bufio"
	"context"
	crand "crypto/rand"
	"encoding/hex"
	stderrors "errors"
	"io"
	"net"
	"net/http"
	"strconv"
	"strings"
	"time"

	boundaryerrors "socialpredict/errors"
	"socialpredict/logger"
)

const (
	requestIDHeader = logger.RequestIDHeader
)

type requestIDContextKey struct{}

// RequestBoundaryMiddleware attaches stable request correlation and completion logging at the HTTP boundary.
func RequestBoundaryMiddleware() func(http.Handler) http.Handler {
	return newRequestBoundaryMiddleware(logger.Standard(), time.Now, defaultRequestID)
}

// RequestIDFromContext returns the boundary request identifier when middleware has attached one.
func RequestIDFromContext(ctx context.Context) string {
	if ctx == nil {
		return ""
	}

	requestID, _ := ctx.Value(requestIDContextKey{}).(string)
	return requestID
}

func newRequestBoundaryMiddleware(runtimeLogger *logger.RuntimeLogger, now func() time.Time, newRequestID func() string) func(http.Handler) http.Handler {
	if runtimeLogger == nil {
		runtimeLogger = logger.Standard()
	}
	if now == nil {
		now = time.Now
	}
	if newRequestID == nil {
		newRequestID = defaultRequestID
	}

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			startedAt := now()
			requestID := incomingRequestID(r, newRequestID)

			w.Header().Set(requestIDHeader, requestID)
			ctx := context.WithValue(r.Context(), requestIDContextKey{}, requestID)
			ctx = logger.ContextWithRequestCorrelation(ctx, requestID, r.Header.Get("Traceparent"))
			r = r.WithContext(ctx)

			recorder := &requestBoundaryWriter{
				ResponseWriter: w,
				statusCode:     http.StatusOK,
			}

			defer func() {
				if recovered := recover(); recovered != nil {
					if !recorder.wroteHeader {
						writeRecoveredPanicResponse(recorder)
					} else {
						recorder.statusCode = http.StatusInternalServerError
					}

					runtimeLogger.Error(
						"middleware",
						"request panic recovered",
						stderrors.New("panic recovered"),
						append(
							requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), boundaryerrors.RuntimeErrorTypePanic),
							logger.ExceptionRecorded(),
						)...,
					)
				}
			}()

			next.ServeHTTP(recorder, r)

			fields := requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), runtimeFailureErrorType(recorder.statusCode))

			switch {
			case recorder.statusCode >= http.StatusInternalServerError:
				runtimeLogger.Error("middleware", "request failed", nil, fields...)
			case recorder.statusCode >= http.StatusBadRequest:
				runtimeLogger.Warn("middleware", "request completed with client error", fields...)
			default:
				runtimeLogger.Info("middleware", "request completed", fields...)
			}
		})
	}
}

func requestBoundaryFields(r *http.Request, requestID string, statusCode int, duration time.Duration, errorType string) []logger.Field {
	fields := []logger.Field{
		logger.Operation("RequestBoundary"),
		logger.RequestID(requestID),
		logger.Method(requestMethod(r)),
		logger.Path(requestPath(r)),
		logger.StatusCode(statusCode),
		logger.DurationMS(duration),
	}
	if address := strings.TrimSpace(getClientIP(r)); address != "" {
		fields = append(fields, logger.Address(address))
	}
	fields = append(fields, logger.TraceContextFromTraceparent(r.Header.Get("Traceparent"))...)
	if strings.TrimSpace(errorType) != "" {
		fields = append(fields, logger.ErrorType(errorType))
	}

	return fields
}

func writeRecoveredPanicResponse(w http.ResponseWriter) {
	boundaryerrors.WriteInternalServerError(w)
}

func runtimeFailureErrorType(statusCode int) string {
	errorType, ok := boundaryerrors.RuntimeFailureErrorType(statusCode)
	if !ok {
		return ""
	}
	return errorType
}

func defaultRequestID() string {
	var raw [16]byte
	if _, err := crand.Read(raw[:]); err == nil {
		return hex.EncodeToString(raw[:])
	}

	return strconv.FormatInt(time.Now().UnixNano(), 16)
}

func incomingRequestID(r *http.Request, newRequestID func() string) string {
	if r != nil {
		if requestID := strings.TrimSpace(r.Header.Get(requestIDHeader)); requestID != "" {
			return requestID
		}
	}

	return newRequestID()
}

func requestMethod(r *http.Request) string {
	if r == nil {
		return ""
	}
	return strings.TrimSpace(r.Method)
}

func requestPath(r *http.Request) string {
	if r == nil || r.URL == nil {
		return ""
	}

	path := strings.TrimSpace(r.URL.EscapedPath())
	if path == "" {
		return "/"
	}
	return path
}

type requestBoundaryWriter struct {
	http.ResponseWriter
	statusCode  int
	wroteHeader bool
}

func (w *requestBoundaryWriter) Header() http.Header {
	return w.ResponseWriter.Header()
}

func (w *requestBoundaryWriter) WriteHeader(statusCode int) {
	w.statusCode = statusCode
	w.wroteHeader = true
	w.ResponseWriter.WriteHeader(statusCode)
}

func (w *requestBoundaryWriter) Write(data []byte) (int, error) {
	if !w.wroteHeader {
		w.wroteHeader = true
	}
	return w.ResponseWriter.Write(data)
}

func (w *requestBoundaryWriter) Flush() {
	flusher, ok := w.ResponseWriter.(http.Flusher)
	if !ok {
		return
	}
	flusher.Flush()
}

func (w *requestBoundaryWriter) Hijack() (net.Conn, *bufio.ReadWriter, error) {
	hijacker, ok := w.ResponseWriter.(http.Hijacker)
	if !ok {
		return nil, nil, http.ErrNotSupported
	}
	return hijacker.Hijack()
}

func (w *requestBoundaryWriter) Push(target string, opts *http.PushOptions) error {
	pusher, ok := w.ResponseWriter.(http.Pusher)
	if !ok {
		return http.ErrNotSupported
